module RefModule(
    input clk,
    input rst,
    input en,
    output [3:0] count
);reg [3:0] count_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst) begin
            count_reg <= 4'b0;
        end else if (en) begin
            count_reg <= count_reg + 1;
        end
    end

    assign count = count_reg;

endmodule
